const j = $json || {};
let md = '';
if (j.message && j.message.content) { md = j.message.content; }
else if (j.content && j.content[0] && j.content[0].text) { md = j.content[0].text; }
else if (typeof j.markdown === 'string') { md = j.markdown; }
md = md || '';
const top = md.split(/\n/).filter(function(l){ return /ransomware|breach|cyber|threat|vulnerab|hacker|malware|attack/i.test(l); }).slice(0,4).join('; ') || 'the global cyber threat landscape this week';
const style = 'Dramatic cinematic cybersecurity magazine cover artwork, vertical portrait composition. A hooded figure silhouette (no visible face) facing a glowing holographic security shield with a padlock, a futuristic illuminated city skyline at night with water reflections, and a constellation of glowing blue network nodes and connections. Deep navy and electric-blue (#2E9BE6) palette, high-contrast, premium and professional. Keep the LEFT THIRD darker and uncluttered for text overlay. NO text, NO words, NO logos, NO readable code, NO watermark.';
return [{ json: { markdown: md || 'No data available for this period.', date: new Date().toISOString().slice(0,10), coverPrompt: style + ' Visual theme inspired by: ' + top } }];

let raw = ($json && $json.markdown) || '';
function tryParse(s){ try { return JSON.parse(s); } catch(e){ return null; } }
function repair(s){ var i0=s.indexOf('{'); if(i0<0) return null; s=s.slice(i0); var stack=[],inStr=false,esc=false,cut=-1,cutStack=null; for(var i=0;i<s.length;i++){ var ch=s[i]; if(esc){esc=false;continue;} if(ch==='\\'){esc=true;continue;} if(ch==='"'){inStr=!inStr;continue;} if(inStr)continue; if(ch==='{'||ch==='['){stack.push(ch);} else if(ch==='}'||ch===']'){stack.pop(); cut=i+1; cutStack=stack.slice();} } if(cut<0) return null; var out=s.slice(0,cut); for(var k=cutStack.length-1;k>=0;k--){ out += cutStack[k]==='{' ? '}' : ']'; } return out; }
var cleaned = raw.replace(/^﻿/,'').trim().replace(/^```(?:json)?\s*/i,'').replace(/\s*```$/i,'').trim();
var data = tryParse(cleaned);
if(!data){ var m = cleaned.match(/\{[\s\S]*\}/); if(m) data = tryParse(m[0]); }
if(!data){ var rep = repair(cleaned); if(rep) data = tryParse(rep); }
// embed remote article images as data URIs (reliable in the PDF engine)
async function embedImg(o){ if(!o) return; var im=(o.image||'').toString(); if(!/^https?:\/\//i.test(im)) return; try{ var r=await this.helpers.httpRequest({ method:'GET', url:im, encoding:'arraybuffer', returnFullResponse:true, timeout:15000, headers:{ 'User-Agent':'Mozilla/5.0 (compatible; JarvisBrief/1.0)','Accept':'image/avif,image/webp,image/*,*/*' } }); var ct=((r&&r.headers&&(r.headers['content-type']||r.headers['Content-Type']))||'').toString().split(';')[0].trim().toLowerCase(); var buf=Buffer.isBuffer(r.body)?r.body:Buffer.from(r.body||''); if(/^image\/(jpeg|jpg|png|gif|webp)$/.test(ct) && buf.length>200 && buf.length<4500000){ o.image='data:'+ct+';base64,'+buf.toString('base64'); } else { o.image=''; } }catch(e){ o.image=''; } }
if(data){ var _imgs=[]; if(data.feature) _imgs.push(data.feature); if(Array.isArray(data.featured)) _imgs=_imgs.concat(data.featured); for(var _ii=0;_ii<_imgs.length;_ii++){ await embedImg.call(this,_imgs[_ii]); } }
const date = ($json && $json.date) || new Date().toISOString().slice(0,10);
const fs = require('fs');
function fileUri(base){ var t=[['/config/branding/'+base+'.png','image/png'],['/config/branding/'+base+'.jpg','image/jpeg'],['/config/branding/'+base+'.jpeg','image/jpeg']]; for(var i=0;i<t.length;i++){ try { return 'data:'+t[i][1]+';base64,'+fs.readFileSync(t[i][0]).toString('base64'); } catch(e){} } return ''; }
const cover=fileUri('cyber-cover')||fileUri('cover'), banner=fileUri('cyber-banner')||fileUri('banner'), avatar=fileUri('jarvis-avatar');
let hero=''; try { var hb=$('Generate Cover (Image Provider)').first().json.data[0].b64_json; if(hb) hero='data:image/png;base64,'+hb; } catch(e){ hero=''; }
if(!hero){ hero = fileUri('cyber-hero') || fileUri('hero') || cover || banner; }
var SECIMG={}; try{ SECIMG=$('Collect Section Images').first().json.sectionImages||{}; }catch(e){ SECIMG={}; }
function ord(n){ var s=['th','st','nd','rd'], v=n%100; return n+(s[(v-20)%10]||s[v]||s[0]); }
function prettyDate(d){ try { var p=(d||'').split('-'); var dt=new Date(Number(p[0]),Number(p[1])-1,Number(p[2])); var M=['January','February','March','April','May','June','July','August','September','October','November','December']; return M[dt.getMonth()]+' '+ord(dt.getDate())+' '+dt.getFullYear(); } catch(e){ return d; } }
const dateStr=prettyDate(date), weekOf=(data&&data.weekOf)?data.weekOf:dateStr;
function esc(s){ return (s==null?'':String(s)).replace(/[&<>]/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;'})[c];}); }

var BCSS='*{box-sizing:border-box} body{margin:0;font-family:-apple-system,"Segoe UI",Arial,sans-serif;color:#11151c;font-size:14px;line-height:1.55} '
