 + '.bonus p{font-size:14px;line-height:1.72;margin:0 0 10px} .secintro{font-size:13.5px;line-height:1.62;color:#3a4452;margin:0 0 14px;font-style:italic} '
 + '.metrics{display:flex;flex-wrap:wrap;gap:10px;margin:8px 0 14px} .metric{flex:1 1 0;min-width:118px;border:1px solid #E2E6EC;border-radius:8px;padding:10px 12px;background:#F4F8FC} .metric .nm{font-size:10px;color:#5A6472;text-transform:uppercase;letter-spacing:.6px} .metric .vl{font-family:Georgia,serif;font-size:19px;font-weight:700;color:#0A1A2F;margin:4px 0 2px} .metric .ch{font-size:11.5px;font-weight:700} '
