var REFS=[]; function refMark(title,source,url){ if(!url || !/^https?:\/\//.test(String(url))) return ''; REFS.push({n:REFS.length+1,title:title,source:source||'',url:url}); return '<sup class="refn">['+REFS.length+']</sup>'; }
function refsSection(){ if(!REFS.length) return ''; var items=REFS.map(function(x){ return '<li><span class="rt">'+esc(x.title)+'</span>'+(x.source?(' — '+esc(x.source)):'')+'<br><a href="'+x.url+'">'+esc(x.url)+'</a></li>'; }).join(''); return secH('Verify','References & Sources')+'<p class="secintro">Every item in this issue is drawn from public sources — follow the links to verify.</p><ol class="refs">'+items+'</ol></div>'; }
function secH(kick,title,first){ return '<div class="sec'+(first?' first':'')+'"><h2 class="h"><span class="kick">'+esc(kick)+'</span>'+esc(title)+'</h2>'; }
function secHero(kick,title,key){ var img=SECIMG[key]; if(!img) return secH(kick,title); return '<div class="sec"><div class="sechero" style="background-image:url('+img+')"><div class="shg"></div><div class="sht"><div class="shk">'+esc(kick)+'</div><div class="shttl">'+esc(title)+'</div></div></div>'; }
function lead(t){ t=(t||'').toString().trim(); if(!t)return''; var parts=t.split(/\n+/).map(function(x){return x.trim();}).filter(function(x){return x;}); if(!parts.length)return''; var h='<p class="lead"><span class="dc">'+esc(parts[0].charAt(0))+'</span>'+esc(parts[0].slice(1))+'</p>'; for(var i=1;i<parts.length;i++){ h+='<p class="lead" style="margin-top:10px">'+esc(parts[i])+'</p>'; } return h; }
function secIntro(t){ t=(t==null?'':String(t)).trim(); if(!t)return''; return '<p class="secintro">'+esc(t)+'</p>'; }
function feature(s){ var im=(s.image||'').toString(); var ph=(/^https?:\/\//.test(im)||im.indexOf('data:')===0)?'<div class="ph" style="background-image:url('+im+')"></div>':''; var u=(s.url||'').toString(); var hd=/^https?:\/\//.test(u)?('<a href="'+u+'" style="color:#0A1A2F;text-decoration:none">'+esc(s.headline)+'</a>'):esc(s.headline); var mark=refMark(s.headline,s.source,s.url); var src=(s.source||'').toString(); var link=/^https?:\/\//.test(u)?('<a href="'+u+'">Read the full story &rsaquo;</a>'):(src?'<span style="color:#5A6472;font-size:12.5px">Source: '+esc(src)+'</span>':''); return '<div class="feature">'+ph+'<div class="fb"><h3>'+hd+mark+'</h3><p>'+esc(s.story)+'</p>'+link+'</div></div>'; }
function card(title,pairs,ref){ var mark=ref?refMark(title,ref.source,ref.url):''; var b=pairs.map(function(p){ var v=p[1]; var cell; if(v && typeof v==='object'){ if(!v.url && !v.text) return ''; cell=(v.url&&/^https?:\/\//.test(v.url))?('<a href="'+v.url+'" style="color:#2E9BE6;text-decoration:none">'+esc(v.text||v.url)+'</a>'):esc(v.text||''); } else { v=(v==null||v==='')?'Not specified':v; cell=/^https?:\/\//.test(String(v))?('<a href="'+v+'" style="color:#2E9BE6;text-decoration:none">'+esc(v)+'</a>'):esc(v); } return '<div class="row"><span class="lab">'+esc(p[0])+'</span>'+cell+'</div>'; }).join(''); return '<div class="co"><div class="hd">'+esc(title)+mark+'</div><div class="bd">'+b+'</div></div>'; }
function snapshot(s){ if(!s)return''; var ms=s.metrics||[]; var cards=ms.map(function(p){ return '<div class="metric"><div class="nm">'+esc(p.name)+'</div><div class="vl">'+esc(p.value||'—')+'</div>'+(p.note?('<div class="ch" style="color:#5A6472">'+esc(p.note)+'</div>'):'')+'</div>'; }).join(''); var h=''; if(cards)h+='<div class="metrics">'+cards+'</div>'; if(s.outlook)h+='<div class="callout"><b>Outlook:</b> '+esc(s.outlook)+'</div>'; return h; }
function bigFeature(f){ if(!f)return''; var im=(f.image||'').toString(); var ph=(/^https?:\/\//.test(im)||im.indexOf('data:')===0)?'<div class="bfimg" style="background-image:url('+im+')"></div>':''; var body=(f.body?String(f.body).split(/\n+/).map(function(p){return p.trim();}).filter(function(p){return p;}).map(function(p){return '<p>'+esc(p)+'</p>';}).join(''):''); var tk=(f.takeaways&&f.takeaways.length)?('<div class="tk"><div class="tkh">Key takeaways</div><ul>'+f.takeaways.map(function(t){return '<li>'+esc(t)+'</li>';}).join('')+'</ul></div>'):''; var u=(f.url||'').toString(); var mark=refMark(f.headline,f.source,f.url); var hd=/^https?:\/\//.test(u)?('<a href="'+u+'" style="color:#0A1A2F;text-decoration:none">'+esc(f.headline)+'</a>'):esc(f.headline); var src=(f.source||'').toString(); var link=/^https?:\/\//.test(u)?('<a href="'+u+'">Read the full story &rsaquo;</a>'):(src?'<span class="src">Source: '+esc(src)+'</span>':''); return '<div class="bf">'+ph+'<div class="bfb">'+(f.headline?'<h3 style="font-family:Georgia,serif;font-size:20px;color:#0A1A2F;margin:0 0 6px">'+hd+mark+'</h3>':'')+(f.deck?'<div class="bfdeck">'+esc(f.deck)+'</div>':'')+'<div class="bftext">'+body+'</div>'+tk+link+'</div></div>'; }
function tips(arr){ if(!arr||!arr.length)return ''; return '<ol class="tips">'+arr.map(function(t){ if(typeof t==='string') return '<li>'+esc(t)+'</li>'; return '<li><b>'+esc(t.tip||t.title||'')+'</b>'+(t.detail?(' &mdash; '+esc(t.detail)):'')+'</li>'; }).join('')+'</ol>'; }

function bodyInner(){
